/**
 * Comparador BPMN (XML) desde STRINGS
 * - Ignora IDs y valores volátiles
 * - Compara lógica real (gateways, sequenceFlows, condiciones)
 * - Devuelve diferencias en JSON legible
 */

/* =========================
   CARGA XML DESDE STRING
   ========================= */

function cargarXMLDesdeTexto(string $xml): DOMXPath
{
    $dom = new DOMDocument();
    $dom->preserveWhiteSpace = false;
    $dom->formatOutput = false;

    if (!@$dom->loadXML($xml)) {
        throw new Exception("XML inválido");
    }

    $xpath = new DOMXPath($dom);
    $xpath->registerNamespace(
        'bpmn',
        'http://www.omg.org/spec/BPMN/20100524/MODEL'
    );

    return $xpath;
}

/* =========================
   NORMALIZADORES
   ========================= */

/**
 * Normaliza referencias tipo node_12345
 */
function normalizarRef(string $ref): string
{
    return preg_replace('/node_\d+/i', 'NODE', trim($ref));
}

/**
 * Normaliza expresiones formales BPMN
 */
function normalizarCondicion(string $condicion): string
{
    $condicion = trim($condicion);
    $condicion = preg_replace('/\s+/', ' ', $condicion);
    $condicion = str_replace(['"', "'"], '', $condicion);
    return $condicion;
}

/**
 * Extrae y normaliza textos de nodos hijos
 */
function obtenerTextos(DOMXPath $xp, DOMNode $ctx, string $path): array
{
    $res = [];
    foreach ($xp->query($path, $ctx) as $n) {
        $res[] = normalizarRef($n->textContent);
    }
    sort($res);
    return $res;
}

/* =========================
   NORMALIZACIÓN BPMN
   ========================= */

function normalizarInclusiveGateways(DOMXPath $xp): array
{
    $resultado = [];

    foreach ($xp->query('//bpmn:inclusiveGateway') as $g) {
        $resultado[] = [
            'type' => 'inclusiveGateway',
            'gatewayDirection' => $g->getAttribute('gatewayDirection'),
            'incoming' => obtenerTextos($xp, $g, 'bpmn:incoming'),
            'outgoing' => obtenerTextos($xp, $g, 'bpmn:outgoing')
        ];
    }

    sort($resultado);
    return $resultado;
}

function normalizarSequenceFlows(DOMXPath $xp): array
{
    $resultado = [];

    foreach ($xp->query('//bpmn:sequenceFlow') as $f) {
        $condicion = '';
        $c = $xp->query('bpmn:conditionExpression', $f);
        if ($c->length > 0) {
            $condicion = normalizarCondicion($c->item(0)->textContent);
        }

        $resultado[] = [
            'type' => 'sequenceFlow',
            'source' => normalizarRef($f->getAttribute('sourceRef')),
            'target' => normalizarRef($f->getAttribute('targetRef')),
            'condition' => $condicion
        ];
    }

    sort($resultado);
    return $resultado;
}

/* =========================
   COMPARACIÓN
   ========================= */

function compararSeccion(array $a, array $b, string $nombre): ?array
{
    if ($a === $b) {
        return null;
    }

    return [
        'section' => $nombre,
        'xml_1' => $a,
        'xml_2' => $b
    ];
}

/* =========================
   FUNCIÓN PRINCIPAL
   ========================= */

function compararBPMN(string $xml1, string $xml2): string
{
    try {
        $xp1 = cargarXMLDesdeTexto($xml1);
        $xp2 = cargarXMLDesdeTexto($xml2);
    } catch (Exception $e) {
        return json_encode([
            'error' => $e->getMessage()
        ], JSON_PRETTY_PRINT);
    }

    $diferencias = [];

    $r = compararSeccion(
        normalizarInclusiveGateways($xp1),
        normalizarInclusiveGateways($xp2),
        'InclusiveGateways'
    );
    if ($r) $diferencias[] = $r;

    $r = compararSeccion(
        normalizarSequenceFlows($xp1),
        normalizarSequenceFlows($xp2),
        'SequenceFlows'
    );
    if ($r) $diferencias[] = $r;

    return json_encode([
        'equals' => empty($diferencias),
        'difference_count' => count($diferencias),
        'differences' => $diferencias
    ], JSON_PRETTY_PRINT | JSON_UNESCAPED_UNICODE);
}

